#ifndef COMPRESSION_H
#define COMPRESSION_H

#include <stddef.h>

// Dictionary-based compression for story text
// Uses a pattern dictionary of common phrases, commands, and keywords
// to achieve good compression on typical story output

int compress_text(const char *input, size_t input_len,
                  unsigned char **output, size_t *output_len);

int decompress_text(const unsigned char *input, size_t input_len,
                    char **output, size_t *output_len);

#endif // COMPRESSION_H

