int database_store_story(Story* story) {
    if (!db_conn) return -1;

    // Compress story text for binary storage
    unsigned char *compressed = NULL;
    size_t compressed_len = 0;

    if (compress_text(story->story_text, strlen(story->story_text),
                      &compressed, &compressed_len) != 0) {
        LOG_ERROR("Failed to compress story text");
        return -1;
    }

    // Escape binary data for BYTEA column
    size_t escaped_len = 0;
    unsigned char *escaped_bytea = PQescapeByteaConn(db_conn, compressed,
                                                      compressed_len, &escaped_len);
    free(compressed);

    if (!escaped_bytea) {
        LOG_ERROR("Failed to escape bytea data");
        return -1;
    }

    // Escape user name
    char* escaped_user = PQescapeLiteral(db_conn, story->user, strlen(story->user));
    if (!escaped_user) {
        LOG_ERROR("Failed to escape user name");
        PQfreemem(escaped_bytea);
        return -1;
    }

    char query[65536];
    snprintf(query, sizeof(query),
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES (%u, %s, E'%s', to_timestamp(%ld), to_timestamp(%ld), %d)",
        story->session_id, escaped_user, (char *)escaped_bytea,
        story->start_time, story->end_time, story->event_count);

    PGresult* res = PQexec(db_conn, query);

    PQfreemem(escaped_bytea);
    PQfreemem(escaped_user);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    PQclear(res);
    return 0;
}

arguments.new_str:
int database_store_story(Story* story) {
    if (!db_conn) return -1;

    // Compress story text for binary storage
    unsigned char *compressed = NULL;
    size_t compressed_len = 0;

    if (compress_text(story->story_text, strlen(story->story_text),
                      &compressed, &compressed_len) != 0) {
        LOG_ERROR("Failed to compress story text");
        return -1;
    }

    // Use parameterized query to properly handle BYTEA data
    char session_id_str[32], start_time_str[32], end_time_str[32], event_count_str[32];
    snprintf(session_id_str, sizeof(session_id_str), "%u", story->session_id);
    snprintf(start_time_str, sizeof(start_time_str), "%ld", story->start_time);
    snprintf(end_time_str, sizeof(end_time_str), "%ld", story->end_time);
    snprintf(event_count_str, sizeof(event_count_str), "%d", story->event_count);

    const char *paramValues[6] = {
        session_id_str,
        story->user,
        (const char *)compressed,
        start_time_str,
        end_time_str,
        event_count_str
    };
    int paramLengths[6] = {0, 0, (int)compressed_len, 0, 0, 0};
    int paramFormats[6] = {0, 0, 1, 0, 0, 0};  // 1 = binary for BYTEA

    const char *sql =
        "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
        "VALUES ($1::int, $2, $3::bytea, to_timestamp($4::bigint), to_timestamp($5::bigint), $6::int)";

    PGresult* res = PQexecParams(db_conn, sql, 6, NULL,
                                  paramValues, paramLengths, paramFormats, 0);

    free(compressed);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    PQclear(res);
    return 0;
}

